# ─── Metrics ────────────────────────────────────────────────────────────────

# Counter: total HTTP requests by user, session, path, method, status
http_requests_total = Counter(
    "http_requests_total",
    "Total HTTP requests",
    ["user_id", "session_id", "path", "method", "status_code"],
)

# Histogram: request duration by user, session, path, method
http_request_duration_seconds = Histogram(
    "http_request_duration_seconds",
    "HTTP request duration in seconds",
    ["user_id", "session_id", "path", "method"],
    buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0),
)

# Gauge: currently in-flight requests per user
http_requests_in_progress = Gauge(
    "http_requests_in_progress",
    "Number of HTTP requests currently being processed",
    ["user_id", "session_id", "path"],
)

# Counter: unique user-path combinations seen
unique_user_path_combinations = Counter(
    "unique_user_path_combinations_total",
    "Number of times a unique user-path combination has been seen",
    ["user_id", "path"],
)

# Gauge: tracks the number of distinct user-path combos discovered
unique_user_path_gauge = Gauge(
    "unique_user_path_distinct_count",
    "Total number of distinct user-path combinations discovered",
)

# ─── Track unique user-path combos ──────────────────────────────────────────

_seen_user_paths = set()
_seen_lock = threading.Lock()


def track_user_path_combination(user_id: str, path: str):
    """Register a new unique user-path combination and create/increment its metric."""
    key = (user_id, path)
    unique_user_path_combinations.labels(user_id=user_id, path=path).inc()
    with _seen_lock:
        if key not in _seen_user_paths:
            _seen_user_paths.add(key)
            unique_user_path_gauge.set(len(_seen_user_paths))


# ─── Per-user-path dynamic metrics registry ─────────────────────────────────

_dynamic_metrics = {}
_dynamic_lock = threading.Lock()


def get_or_create_user_path_counter(user_id: str, path: str):
    """
    Return (or lazily create) a dedicated Counter for a specific user+path
    combination.  This gives you one metric *per* unique pair, which is useful
    for detailed traffic analysis dashboards.
    """
    key = (user_id, path)
    if key not in _dynamic_metrics:
        with _dynamic_lock:
            if key not in _dynamic_metrics:
                safe_user = user_id.replace("-", "_").replace(".", "_")
                safe_path = (
                    path.strip("/").replace("/", "_").replace("-", "_") or "root"
                )
                metric_name = f"user_path_hits__{safe_user}__{safe_path}"
                # Avoid duplicate registration
                try:
                    counter = Counter(
                        metric_name,
                        f"Hit count for user={user_id} path={path}",
                    )
                except ValueError:
                    # Already registered (race or restart) – look it up
                    counter = None
                _dynamic_metrics[key] = counter
    counter = _dynamic_metrics.get(key)
    if counter is not None:
        counter.inc()
    return counter


# ─── HTTP handler ────────────────────────────────────────────────────────────


class TrafficAnalysisHandler(BaseHTTPRequestHandler):
    """Simple HTTP server that instruments every request with Prometheus metrics."""

    def _extract_ids(self):
        """Pull user_id and session_id from query-string or headers."""
        parsed = urlparse(self.path)
        qs = parse_qs(parsed.query)
        user_id = (
            qs.get("user_id", [None])[0]
            or self.headers.get("X-User-Id")
            or "anonymous"
        )
        session_id = (
            qs.get("session_id", [None])[0]
            or self.headers.get("X-Session-Id")
            or "unknown"
        )
        # Use the path without query string for the label
        clean_path = parsed.path
        return user_id, session_id, clean_path

    def _handle(self, method: str):
        user_id, session_id, path = self._extract_ids()

        # In-flight gauge
        http_requests_in_progress.labels(
            user_id=user_id, session_id=session_id, path=path
        ).inc()

        start = time.time()
        try:
            # ── Route logic ──────────────────────────────────────────────
            if path == "/metrics":
                self._serve_metrics()
                status_code = 200
            elif path == "/health":
                self._respond(200, "OK")
                status_code = 200
            elif path.startswith("/api/"):
                # Simulate some work
                time.sleep(random.uniform(0.01, 0.15))
                self._respond(200, f"Hello user={user_id}, session={session_id}, path={path}")
                status_code = 200
            else:
                self._respond(404, "Not Found")
                status_code = 404

        except Exception:
            self._respond(500, "Internal Server Error")
            status_code = 500
        finally:
            duration = time.time() - start

            # Record metrics
            http_requests_total.labels(
                user_id=user_id,
                session_id=session_id,
                path=path,
                method=method,
                status_code=str(status_code),
            ).inc()

            http_request_duration_seconds.labels(
                user_id=user_id,
                session_id=session_id,
                path=path,
                method=method,
            ).observe(duration)

            http_requests_in_progress.labels(
                user_id=user_id, session_id=session_id, path=path
            ).dec()

            # Unique user-path tracking
            track_user_path_combination(user_id, path)

            # Dynamic per-user-path counter
            get_or_create_user_path_counter(user_id, path)

    # ── HTTP verbs ───────────────────────────────────────────────────────
    def do_GET(self):
        self._handle("GET")

    def do_POST(self):
        self._handle("POST")

    def do_PUT(self):
        self._handle("PUT")

    def do_DELETE(self):
        self._handle("DELETE")

    # ── Helpers ──────────────────────────────────────────────────────────
    def _respond(self, code: int, body: str):
        self.send_response(code)
        self.send_header("Content-Type", "text/plain; charset=utf-8")
        self.end_headers()
        self.wfile.write(body.encode())

    def _serve_metrics(self):
        output = generate_latest(REGISTRY)
        self.send_response(200)
        self.send_header("Content-Type", "text/plain; version=0.0.4; charset=utf-8")
        self.end_headers()
        self.wfile.write(output)

    # Suppress default logging per-request (optional)
    def log_message(self, fmt, *args):
        print(f"[{self.log_date_time_string()}] {fmt % args}")


# ─── Simulated traffic generator (for demo / testing) ───────────────────────


def simulate_traffic(host: str = "127.0.0.1", port: int = 8000, count: int = 50):
    """Fire random requests to exercise the metrics."""
    import urllib.request

    users = ["user_1", "user_2", "user_3", "anonymous"]
    sessions = ["sess_aaa", "sess_bbb", "sess_ccc"]
    paths = [
        "/api/products",
        "/api/products/42",
        "/api/cart",
        "/api/checkout",
        "/api/user/profile",
        "/unknown/page",
        "/health",
    ]

    for i in range(count):
        user = random.choice(users)
        sess = random.choice(sessions)
        path = random.choice(paths)
        url = f"http://{host}:{port}{path}?user_id={user}&session_id={sess}"
        try:
            urllib.request.urlopen(url, timeout=5)
        except Exception as exc:
            print(f"  simulated request #{i} failed: {exc}")
        time.sleep(random.uniform(0.02, 0.1))

    print(f"\n✅  Simulated {count} requests.  Check http://{host}:{port}/metrics\n")


