def main():
    host = "0.0.0.0"
    port = 8000

    server = HTTPServer((host, port), TrafficAnalysisHandler)
    print(f"🚀  Server listening on http://{host}:{port}")
    print(f"📊  Metrics at http://{host}:{port}/metrics")
    print(f"💚  Health at http://{host}:{port}/health")
    print()

    # Start simulated traffic in background after a short delay
    def _delayed_sim():
        time.sleep(2)
        print("🔄  Starting simulated traffic …")
        simulate_traffic("127.0.0.1", port, count=30)

    sim_thread = threading.Thread(target=_delayed_sim, daemon=True)
    sim_thread.start()

    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\n🛑  Shutting down.")
        server.shutdown()


if __name__ == "__main__":
    main()